#include<cstdio>
#include<vector>
#include<algorithm>
#define SIZ(a) (int(a.size()))
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline void chkmin(int &x,const int &w){w<x?x=w:0;}
inline int min(const int &x,const int &y){return x<y?x:y;}
inline int max(const int &x,const int &y){return x<y?y:x;}
const int N=3e5+10;std::vector<int> G1[N],G2[N],T[N];
int n,m,dfn[N],low[N],stk[N],top,scc[N],cdt,tot,w[N],d2[N],Rt,Q,deg[N],K;bool iss[N];
inline void tarjan(const int &u)
{
	low[u]=dfn[u]=++cdt;iss[stk[++top]=u]=true; 
	for(int v: G1[u])
	{
		if(!dfn[v]){tarjan(v);chkmin(low[u],low[v]);}
		else if(iss[v]) chkmin(low[u],low[v]);
	}
	if(low[u]==dfn[u]){int v;++tot;do{iss[v=stk[top--]]=false;++w[scc[v]=tot];}while(u!=v);}
}
inline void topo()
{
	rep(1,tot,i)if(!deg[i])stk[++top]=i;
	while(top){int u=stk[top--];for(int v: G2[u])if(!(--deg[v]))T[u].push_back(stk[++top]=v),++d2[v];}
	rep(1,tot,i)if(!d2[i]){Rt=i;return;}
}
namespace TreeCut
{
	int siz[N],dep[N],fa[N],top[N],mxs[N],cdt,ql[N],qr[N],S[N],s[N];
	struct node
	{
		int l,r;inline node(const int &x=0,const int &y=0){l=x;r=y;}
		inline bool operator<(const node&Q)const{return l<Q.l;}
	}p[514];int n;
	inline void dfs0(const int &u=Rt)
	{
		S[u]+=w[u];siz[u]=1;int mx=0;for(int v: T[u])
		{
			dep[v]=dep[u]+1;fa[v]=u;S[v]=S[u];dfs0(v);
			siz[u]+=siz[v]; mx<siz[v]?mx=siz[mxs[u]=v]:0;
		}
	}
	inline void dfs1(const int &u=Rt,const int &tp=Rt)
	{
		s[ql[u]=++cdt]=w[u];top[u]=tp;if(mxs[u])dfs1(mxs[u],tp);
		for(int v: T[u])if(v!=mxs[u])dfs1(v,v);qr[u]=cdt;
	}
	inline int LCA(int u,int v)
	{
		while(top[u]!=top[v])dep[top[u]]<dep[top[v]]?v=fa[top[v]]:u=fa[top[u]];
		return dep[u]<dep[v]?u:v;
	}
	inline void Init(){rep(2,cdt,i)s[i]+=s[i-1];}
	inline void Case0(const int &s,const int &t){printf("%d\n",LCA(s,t)==s?S[t]-S[fa[s]]:0);}
	std::vector<int> A,B;inline void add(const int &u,const int &v)
	{
		bool flag=false;for(int v:A)if(ql[v]<=ql[u]&&ql[u]<=qr[v])flag=true;
		if(flag)
		{
			int tg=0;for(int &w:A)
			{
				if(tg==-1)break;if(ql[w]<=ql[v]&&ql[v]<=qr[w])tg=-1;
				if(tg!=-1&&ql[v]<ql[w]&&ql[w]<=qr[v]){tg=1;w=v;}
			}
			rep(0,SIZ(A)-1,i)
			{
				bool flag=false;rep(0,i-1,j)if(A[i]==A[j]){flag=true;}
				if(flag){A.erase(A.begin()+i,A.begin()+i+1);--i;}
			}
			if(!tg)A.push_back(v);
		}
		flag=false;for(int w:B)if(ql[v]<=ql[w]&&ql[w]<=qr[v])flag=true;
		if(flag)
		{
			int tg=0;for(int &w:B)
			{
				if(tg)break;if(ql[u]<=ql[w]&&ql[w]<=qr[u])tg=-1;
				if(!tg&&ql[w]<ql[u]&&ql[u]<=qr[w]){tg=1;w=u;}
			}
			if(!tg)B.push_back(u);
		}
	}
	inline void Query()
	{
		A.clear();B.clear();
		int s=scc[read()],t=scc[read()];A.push_back(s);B.push_back(t);
		int u1=0,v1=0,u2=0,v2=0;if(K>0)u1=scc[read()],v1=scc[read()];if(K>1)u2=scc[read()],v2=scc[read()];
		if(u1==v1)u1=v1=0;if(u2==v2)u2=v2=0;if(u1)add(u1,v1);if(u2)add(u2,v2);if(u1)add(u1,v1);
		int ans=0;for(int c:A)rep(0,SIZ(B)-1,j)
		{
			int d=B[j];if(ql[c]<=ql[d]&&ql[d]<=qr[c])
			{
				int lc=fa[c],glc;rep(0,j-1,k){glc=LCA(B[k],d);if(dep[glc]>dep[lc])lc=glc;}
				ans+=S[d]-S[lc];
			}
		}
		printf("%d\n",ans);return;
	}
}
using TreeCut::LCA;using TreeCut::Case0;using TreeCut::dep;
namespace Sub0{inline void mian(){while(Q--){int s=read(),t=read();Case0(s,t);}}}
int main()
{
	n=read();m=read();Q=read();K=read();
	rep(1,m,i){int x=read();G1[x].push_back(read());} rep(1,n,i)if(!dfn[i])tarjan(i);
	rep(1,n,u)for(int v: G1[u])if(scc[u]!=scc[v])G2[scc[u]].push_back(scc[v]),++deg[scc[v]]; topo();
	TreeCut::dep[Rt]=1;TreeCut::dfs0();TreeCut::dfs1();TreeCut::Init();
	if(K==0){while(Q--){int s=scc[read()],t=scc[read()];Case0(s,t);}return 0;}
	while(Q--)TreeCut::Query();return 0;
}
